code = """import json
import re

with open(locals()['var_function-call-9730938913871448610'], 'r') as f:
    citations = json.load(f)
citation_map = {rec['title']: int(rec['citation_count']) for rec in citations}

with open(locals()['var_function-call-13481044926473905955'], 'r') as f:
    docs1 = json.load(f)
with open(locals()['var_function-call-9128164238513416267'], 'r') as f:
    docs2 = json.load(f)

unique_docs = {d['filename']: d for d in docs1 + docs2}
docs = list(unique_docs.values())

p1 = r"(?:^|[^a-zA-Z0-9])CHI\s*(?:'?\d{2}|20\d{2})"
p2 = r"Conference on Human Factors in Computing Systems"
regex = p1 + "|" + p2
pattern = re.compile(regex, re.IGNORECASE)

chi_papers = []
total_citations = 0

for doc in docs:
    text = doc['text']
    header = text[:10000]
    
    if pattern.search(header):
        title = doc['filename'].replace('.txt', '')
        if title in citation_map:
            count = citation_map[title]
            chi_papers.append({"title": title, "count": count})
            total_citations += count

result = {
    "total_citations": total_citations,
    "chi_paper_count": len(chi_papers),
    "papers": chi_papers
}

print("__RESULT__:")
print(json.dumps(result))"""

